request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?org ?orgName ?model ?modelName WHERE {
  ?model a bboExt:Model .
  ?model tai:belongsTo ?org .
  OPTIONAL { ?org rdfs:label ?orgName . }
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(
    EXISTS { ?model bbo:name ?n . FILTER(CONTAINS(LCASE(STR(?n)), "universit")) }
    || EXISTS { ?model tai:originalId ?o . FILTER(CONTAINS(LCASE(STR(?o)), "universit")) }
    || EXISTS { ?model tai:normalizedId ?m . FILTER(CONTAINS(LCASE(STR(?m)), "universit")) }
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?org ?orgName ?model ?modelName WHERE {
  ?model a bboExt:Model .
  ?model tai:belongsTo ?org .

  OPTIONAL { ?org rdfs:label ?orgName . }
  OPTIONAL { ?model bbo:name ?modelName . }

  FILTER(
    EXISTS {
      ?org rdfs:label ?ol .
      FILTER(CONTAINS(LCASE(STR(?ol)), "univers"))
    }
    || EXISTS {
      ?model bbo:name ?mn .
      FILTER(CONTAINS(LCASE(STR(?mn)), "univers"))
    }
    || EXISTS {
      ?org tai:description ?od .
      FILTER(CONTAINS(LCASE(STR(?od)), "univers"))
    }
    || EXISTS {
      ?model tai:originalId ?oid .
      FILTER(CONTAINS(LCASE(STR(?oid)), "univers"))
    }
  )
}
LIMIT 25
